$(function () {
    $(".add_exo").on("click", function () {
        $(this).css('display', 'none');
        $("#divexoneracion").fadeIn();
        $(".hide_exo").fadeIn();
    });

    $(".hide_exo").on("click", function () {
        $(this).css('display', 'none');
        $("#divexoneracion").fadeOut();
        $(".add_exo").fadeIn();
    });
});
