$(document).on('click', '#addManually', function (e) {
    $('#mnet_price').text('0.00');
    $('#mpro_tax').text('0.00');
    $('#mModal').appendTo("body").modal('show');
    return false;
});

$(document).on('change', '#mprice, #mtax, #mdiscount', function () {
    var unit_price = parseFloat($('#mprice').val());
    var ds = $('#mdiscount').val() ? $('#mdiscount').val() : '0';
    if (ds.indexOf("%") !== -1) {
        var pds = ds.split("%");
        if (!isNaN(pds[0])) {
            item_discount = parseFloat(((unit_price) * parseFloat(pds[0])) / 100);
        } else {
            item_discount = parseFloat(ds);
        }
        // console.log(item_discount);
    } else {
        item_discount = parseFloat(ds);
    }
    unit_price -= item_discount;
    var pr_tax = $('#mtax').val(), item_tax_method = 0;
    var pr_tax_val = 0, pr_tax_rate = 0;
    var tax_rates_fec = JSON.parse(localStorage.getItem('tax_rates_fec'));
    if (pr_tax !== null && pr_tax != 0) {
        $.each(tax_rates_fec, function () {
            if (this.id_impuesto == pr_tax) {
                if (item_tax_method == 0) {
                    pr_tax_val = formatDecimal(((unit_price) * parseFloat(this.tasa_impuesto)) / (100 + parseFloat(this.tasa_impuesto)));
                    pr_tax_rate = formatDecimal(this.tasa_impuesto) + '%';
                    unit_price -= pr_tax_val;
                } else {
                    pr_tax_val = formatDecimal(((unit_price) * parseFloat(this.tasa_impuesto)) / 100);
                    pr_tax_rate = formatDecimal(this.tasa_impuesto) + '%';
                }
            }
        });
    }

    $('#mnet_price').text(formatMoney(unit_price));
    $('#mpro_tax').text(formatMoney(pr_tax_val));
});
$(document).on('click', '#addItemManually', function (e) {
    if(validaciones('#pr_popover_content2')){
        quitarValidaciones('#pr_popover_content2');
        var mid = (new Date).getTime(),
                mcode = $('#mcode').val(),
                mname = $('#mname').val(),
                mtax = $('#mtax').val(),
                mitem_type = $('#mitem_type').val(),
                mqty = parseFloat($('#mquantity').val()),
                mdiscount = $('#mdiscount').val() ? $('#mdiscount').val() : '0',
                unit_price = parseFloat($('#mprice').val()),
                unid_measu = $("#munit").val(),
                mtax_rate = {};
        
        tax_rates_fec = JSON.parse(localStorage.getItem('tax_rates_fec'));
        if (mcode && mname && mqty && unit_price) {
            $.each(tax_rates_fec, function () {
                if (this.id_impuesto == mtax) {
                    mtax_rate = this;
                }
            });

            fecitems[mid] = {"id": mid, "item_id": mid, "label": mname + ' (' + mcode + ')', "price": unit_price, "row": {"id": mid, "code": mcode, "name": mname, "quantity": mqty, "unit": unid_measu, "base_quantity": mqty, "price": unit_price, "unit_price": unit_price, "real_unit_price": unit_price, "tax_rate": mtax, "tax_method": 0, "qty": mqty, "type": mitem_type, "addtype": "manual", "discount": mdiscount, "serial": "", "option": ""}, "tax_rate": mtax_rate, 'units': false, "options": false};
            localStorage.setItem('fecitems', JSON.stringify(fecitems));
            loadItems();
        }
        $('#mModal').modal('hide');
        $('#mcode').val('');
        $('#mname').val('');
        $('#mtax').val('');
        $('#mquantity').val('');
        $('#mdiscount').val('');
        $('#mprice').val('');
    }else{
        bootbox.alert('Debe completar todos los campos en rojo');
        return false;
    }
    
});

function obtenerCanton(element){
    $.ajax({
        type: "get",
        url: base_url + 'FacturasCompras/get_canton',
        async: true,
        data: {id: element},
        dataType: "html",
        success: function (data) {
            $('#codigo_canton').html(data).fadeIn();
        },
        error: function (xhr, ajaxOptions, thrownError) {
            alert(xhr.status);
            alert(thrownError);
        }
    });
    return false;

}

