$(document).on('click', '#editItem', function () {
var row = $('#' + $('#row_id').val());
var item_id = row.attr('data-item-id'), new_pr_tax = $('#ptax').val(), new_pr_tax_rate = false;
var tax_rates_fec = JSON.parse(localStorage.getItem('tax_rates_fec'));
if (new_pr_tax) {
    $.each(tax_rates_fec, function () {
        // console.log(tax_rates_fec);
        if (this.id_impuesto == new_pr_tax) {
            new_pr_tax_rate = this;
        }
    });
}
var price = parseFloat($('#pprice').val());
if (item.options !== false) {
    var opt = $('#poption').val();
    $.each(item.options, function () {
        if (this.id == opt && this.price != 0 && this.price != '' && this.price != null) {
            price = price - parseFloat(this.price);
        }
    });
}
// if (site.settings.product_discount == 1 && $('#pdiscount').val()) {
//     if (!is_valid_discount($('#pdiscount').val())) {
//         bootbox.alert("Se esperaba un valor");
//         return false;
//     }
// }
var pquantity = parseFloat($('#pquantity').val());
if (!is_numeric(pquantity) || parseFloat($('#pquantity').val()) < 0) {
    $(this).val(old_row_qty);
    bootbox.alert("Se esperaba un valor");
    return;
}
var unit = $('#punit').val();
var base_quantity = parseFloat($('#pquantity').val());
// console.log(fecitems[item_id].row.base_unit);
if (unit && fecitems[item_id].units) {
    $.each(fecitems[item_id].units, function () {
        if (this.id == unit) {
            base_quantity = unitToBaseQty($('#pquantity').val(), this);
        }
    });
}
fecitems[item_id].row.fup = 1,
        fecitems[item_id].row.qty = parseFloat($('#pquantity').val()),
        fecitems[item_id].row.base_quantity = parseFloat(base_quantity),
        fecitems[item_id].row.real_unit_price = price,
        fecitems[item_id].row.unit = unit,
        fecitems[item_id].row.tax_rate = new_pr_tax,
        fecitems[item_id].tax_rate = new_pr_tax_rate,
        fecitems[item_id].row.discount = $('#pdiscount').val() ? $('#pdiscount').val() : '',
        fecitems[item_id].row.option = $('#poption').val() ? $('#poption').val() : '',
        fecitems[item_id].row.serial = $('#pserial').val();
localStorage.setItem('fecitems', JSON.stringify(fecitems));
$('#prModal').modal('hide');

loadItems();
return;
});

