function unitToBaseQty(qty, unitObj) {
switch (unitObj.operator) {
    case '*':
        return parseFloat(qty) * parseFloat(unitObj.operation_value);
        break;
    case '/':
        return parseFloat(qty) / parseFloat(unitObj.operation_value);
        break;
    case '+':
        return parseFloat(qty) + parseFloat(unitObj.operation_value);
        break;
    case '-':
        return parseFloat(qty) - parseFloat(unitObj.operation_value);
        break;
    default:
        return parseFloat(qty);
}
}

    
