function saveFec(){
    var TotalServGravados= $('#inp_TotalServGravados').val();
    var TotalServExonerado= $('#inp_TotalServExonerado').val();
    var TotalServExentos = $('#inp_TotalServExentos').val();
    var TotalMercanciasGravadas = $('#inp_TotalMercanciasGravadas').val();
    var TotalMercExonerada = $('#inp_TotalMercExonerada').val();
    var TotalMercanciasExentas = $('#inp_TotalMercanciasExentas').val();
    var TotalGravado = $('#inp_TotalGravado').val();
    var TotalExento= $('#inp_TotalExento').val();
    var TotalExonerado = $('#inp_TotalExonerado').val();
    var TotalVenta = $('#inp_TotalVenta').val();
    var TotalDescuentos = $('#inp_TotalDescuentos').val();
    var TotalVentaNeta = $('#inp_TotalVentaNeta').val();
    var TotalImpuesto = $('#inp_TotalImpuesto').val();
    var TotalComprobante = $('#inp_TotalComprobante').val();
    var payment_status = $('#slpayment_status').val();
    var paymentmethod = $('#paymentmethod').val();
    var paid_by_1 = $('#paid_by_1').val();
    var id_proveedor = $('#userid').val();
    var ExoTipoDocumento =$('#ExoTipoDocumento').val();
    var token_post=$('#token_post').val();
    // .replace('"','').replace('"','')
    var ExoTipoDocumento = localStorage.getItem('exo_t_doc')?localStorage.getItem('exo_t_doc'):'';
    var ExoNumeroDocumento = localStorage.getItem('exo_numero_documento')?localStorage.getItem('exo_numero_documento'):'';
    var ExoNombreInstitucion = localStorage.getItem('exo_nombre_institucion')?localStorage.getItem('exo_nombre_institucion'):'';
    var ExoFechaEmision = localStorage.getItem('exo_fecha_emision')?localStorage.getItem('exo_fecha_emision'):'';
    var ExoPorcentajeExoneracion = localStorage.getItem('porcen_exon_fec')?localStorage.getItem('porcen_exon_fec'):'';
    var jsonTotales = 
    {
        "TotalServGravados":TotalServGravados,
        "TotalServExonerado":TotalServExonerado ,
        "TotalServExentos": TotalServExentos,
        "TotalMercanciasGravadas": TotalMercanciasGravadas,
        "TotalMercExonerada": TotalMercExonerada,
        "TotalMercanciasExentas": TotalMercanciasExentas,
        "TotalGravado":TotalGravado ,
        "TotalExento": TotalExento,
        "TotalExonerado":TotalExonerado ,
        "TotalVenta": TotalVenta,
        "TotalDescuentos":TotalDescuentos ,
        "TotalVentaNeta":TotalVentaNeta ,
        "TotalImpuesto": TotalImpuesto,
        "TotalComprobante" : TotalComprobante,
        "payment_status": payment_status,
        "paymentmethod": paymentmethod,
        "paid_by_1":paid_by_1,
        "id_proveedor":id_proveedor,
        "exoneracion": {
            "ExoTipoDocumento" : ExoTipoDocumento.replace('"','').replace('"',''),
            "ExoNumeroDocumento" : ExoNumeroDocumento.replace('"','').replace('"',''),
            "ExoNombreInstitucion" : ExoNombreInstitucion.replace('"','').replace('"',''),
            "ExoFechaEmision" : ExoFechaEmision.replace('"','').replace('"',''),
            "ExoPorcentajeExoneracion" : ExoPorcentajeExoneracion.replace('"','').replace('"','')
        },
        "token_post":token_post,
    }
    //----------------ROW-----------------------------------
    var fecitems =JSON.parse(localStorage.getItem('fecitems'));
    var items= [];
    sortedItems = _.sortBy(fecitems, function (o) {
        return [parseInt(o.order)];
    });
    $.each(sortedItems, function () {
        items.push(this);
    } );
    // ---------------------------------------------------------------
    // --------------------MONTO LINEA---------------------------
    var montosLinea =JSON.parse(localStorage.getItem('montosLinea'));
    var lineas= [];
    sortedlineas = _.sortBy(montosLinea, function (o) {
        return [parseInt(o.order)];
    });

    $.each(sortedlineas, function () {
        lineas.push(this);
    } );
    // ---------------------------------------------------------------------

    //----------------------------------------------------------------------
    $.ajax({
        type: "GET",
        url: base_url + 'FacturasCompras/save_fec',
        data: {'myData' : JSON.stringify(items),'totales':JSON.stringify(jsonTotales),'linea':JSON.stringify(lineas)},
        contentType: "application/json; charset=utf-8;",
        dataType: "json",
        success: function (data) {
            if(data[0]=='error'){
                bootbox.alert(data[1]);
            }else{
                bootbox.confirm(data[1], function(result) {
                    localStorage.removeItem('exo_t_doc');
                    localStorage.removeItem('exo_numero_documento');
                    localStorage.removeItem('exo_nombre_institucion');
                    localStorage.removeItem('exo_fecha_emision');
                    localStorage.removeItem('porcen_exon_fec');
                    localStorage.removeItem('fecitems');
                    location.href=base_url + "facturascompras/view_fec/"+data[2];
                });
            }
            
        },
        error: function (xhr, ajaxOptions, thrownError) {
            alert(xhr.responseText);
            alert(xhr.status);
            alert(thrownError);
        }
    });
      console.log(JSON.stringify(items));
}

function validaciones(campos){
    // Fetch all the forms we want to apply custom Bootstrap validation styles to
    var valid = 0;
    var invalid=0;
    $(campos).each(function(){
        $(this).find('input,select').each(function(){
            if(this.hasAttribute('required')){
                if(this.value.length>0){
                    valid++;
                }else{
                    this.style.borderColor = " red";
                    this.setAttribute('onchange','quitarColorCampos(this);');
                    invalid++;
                }
            }
        });
    });
    if(valid>invalid && invalid===0){
        return true;
    }else{
        return false;
    }
}

function cancelar(){
    localStorage.removeItem('exo_t_doc');
    localStorage.removeItem('exo_numero_documento');
    localStorage.removeItem('exo_nombre_institucion');
    localStorage.removeItem('exo_fecha_emision');
    localStorage.removeItem('porcen_exon_fec');
    localStorage.removeItem('fecitems');
    location.href=base_url + "facturascompras/create_fec/";
}

function quitarColorCampos(element){
    if(element.value.length>0){
        element.style.borderColor = "green";
    }else{
        element.style.borderColor = "red";
    }
}

function quitarValidaciones(campos){
    $(campos).each(function(){
        $(this).find('input,select').each(function(){
            this.removeAttribute('style','border-color: white');
        });
    });
}



$("#mModal").on('hidden.bs.modal', function () {
    var e = $(this).find('needs-validation');
    $(this).find('input,select').each(function(){
        this.removeAttribute('style','border-color: white');
        this.value = '';
    });
});


