function obtenerActividades(value, fieldAct, fieldNom, fieldTipo)
{
    if (value.length >= 9)
    {
        var url = 'https://api.hacienda.go.cr/fe/ae?identificacion=' + value;
        $.get(url, function (data) {
            if (data.nombre)
            {
                $(fieldNom).val(data.nombre)
            }

            $(fieldTipo).val(data.tipoIdentificacion);


            if (data.actividades.length > 0) {
                var actividades = data.actividades;
                console.log(actividades);
                var i = 0;
                $.each(actividades, function (key, value) {
                    if (i == 0)
                    {
                        var select = " selected='selected' ";
                        i = i + 1;
                    } else {
                        var select = " ";
                    }
                    $(fieldAct).append("<option " + select + " value='" + value.codigo + "'>" + value.descripcion + " (" + value.codigo + ")</option>");
                });

                $(fieldAct).css('width', '100%');
                $(fieldAct).select2();
                $(fieldAct).trigger('change');
            } else {
                $(fieldAct).html('<input class="form-control parsley-validated" id="actividad_economica" placeholder="" required="true" autocomplete="off" name="actividad_economica" type="text" value="000000">')
            }

        });
    }

    

}

